class Solution:
    def maxScore(self, nums: List[int], x: int) -> int:
        even = nums[0] if nums[0] % 2 == 0 else -float('inf')
        odd = nums[0] if nums[0] % 2 == 1 else -float('inf')

        for num in nums[1:]:
            if num % 2 == 0:
                even = max(even, odd - x + num)
            else:
                odd = max(odd, even - x + num)

        return max(even, odd)
